#include <stdio.h>
#include <stdlib.h>

#define REG_STACK_SIZE 8
#define SPILL_THRESHOLD 6

typedef struct {
    int registers[REG_STACK_SIZE];
    int sp;  // Stack Pointer
    int fp;  // Frame Pointer
    int *spill_area;  // Memory backup for overflow
    int spill_count;
} RegisterStack;

void init_stack(RegisterStack *s) {
    s->sp = 0;
    s->fp = -1;
    s->spill_area = NULL;
    s->spill_count = 0;
}

void push(RegisterStack *s, int value) {
    if (s->sp >= REG_STACK_SIZE) {
        // Spill to memory
        s->spill_area = realloc(s->spill_area, (s->spill_count + 1) * sizeof(int));
        s->spill_area[s->spill_count++] = value;
        printf("Spilled to memory: %d\n", value);
    } else {
        s->registers[s->sp++] = value;
    }
}

int pop(RegisterStack *s) {
    if (s->sp > 0) {
        return s->registers[--s->sp];
    } else if (s->spill_count > 0) {
        return s->spill_area[--s->spill_count];
    }
    printf("Stack Underflow!\n");
    return -1;
}

int main() {
    RegisterStack stack;
    init_stack(&stack);

    printf("Pushing values 10 to 15:\n");
    for (int i = 10; i <= 15; i++) {
        push(&stack, i);
    }

    printf("\nPopping values:\n");
    for (int i = 0; i < 6; i++) {
        printf("Pop: %d\n", pop(&stack));
    }

    return 0;
}
